// Issue magic-link token regardless of whether the email maps to a
// real user (do not leak existence). The verify webhook is where
// existence is enforced. Token: 32-byte base64url (43 chars).
const body = $input.item.json.body || {};
const email = String(body.email || '').trim().toLowerCase();
if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) {
  return { json: { ok: false, status: 400, error: 'valid email required' } };
}
const crypto = require('crypto');
const token = crypto.randomBytes(32).toString('base64url');
const expires_at = new Date(Date.now() + 15 * 60 * 1000).toISOString();
return { json: { ok: true, email, token, expires_at } };

